mapper.select:
SELECT * FROM ( SELECT
FROM tb_stl_earning_mng a ) T
ORDER BY generate_date DESC, id DESC LIMIT #{offset}, #{recordSize}

mapper.insert:
INSERT INTO tb_stl_earning_mng (
	  company_id
	, generate_date
	, create_date
	, create_id
) VALUES (
	  #{companyId}
	, #{generateDate}
	, NOW()
	, #{createId}
)

INSERT INTO tb_stl_earning_list (
	  earning_id
	, agency_name
	, app_date
	, open_date
	, mno
	, contract_num
	, acc_type
	, phone_num
	, acc_name
	, plan_name
	, status
	, create_date
	, create_id
) VALUES (
	  #{earningId}
	, #{agencyName}
	, #{appDate}
	, #{openDate}
	, #{mno}
	, #{contractNum}
	, #{accType}
	, #{phoneNum}
	, #{accName}
	, #{planName}
	, #{status}
	, NOW()
	, #{createId}
)
